export const useComposedRefs = <T>(...refs: React.Ref<T>[]) => {
  return (value: T) => {
    for (const ref of refs) {
      if (typeof ref === "function") ref(value);
      else if (ref != null) (ref as React.MutableRefObject<T>).current = value;
    }
  };
};

